import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface AQIData {
  location: string;
  currentAQI: {
    value: number;
    category: string;
  };
  pollutants: {
    name: string;
    value: number;
    unit: string;
  }[];
}

export default function Widget() {
  const aqiData = response.data as AQIData;
  const { location, currentAQI, pollutants } = aqiData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {location}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#4CAF50', my: 0.5 }}>
              AQI: {currentAQI.value}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Category: {currentAQI.category}
            </Typography>
          </Box>

          <PieChart
            height={150}
            series={[
              {
                data: pollutants.map(p => p.value),
                labels: pollutants.map(p => p.name),
                colors: ['#FF5722', '#FFC107', '#8BC34A', '#00BCD4', '#673AB7'],
              },
            ]}
            sx={{
              '& .MuiPieElement-root': {
                strokeWidth: 1,
              },
              '& .MuiPieLabel-root': {
                fontSize: 10,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {pollutants.map((pollutant, index) => (
              <Chip
                key={index}
                label={`${pollutant.name}: ${pollutant.value} ${pollutant.unit}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
